object Solution { def top_k_words(text: String, k: Int): Seq[Seq[Any]] = { if (k <= 0) return Seq.empty; val counts = scala.collection.mutable.Map[String, Int]().withDefaultValue(0); for (word <- "[a-z]+".r.findAllIn(text.toLowerCase)) counts(word) += 1; counts.toSeq.sortBy { case (word, count) => (-count, word) }.take(k).map { case (word, count) => Seq(word, count) } } }
